# SSH connection timeout in seconds
timeout=5

# Iterate over each server IP
for ip in "${server_ips[@]}"; do
    # Attempt to SSH into the server
    ssh -o BatchMode=yes -o ConnectTimeout=$timeout "ubuntu@$ip" "echo 2>&1" >/dev/null

    # Check the exit status of the SSH command
    if [ $? -eq 0 ]; then
        echo "$ip,accessible" >> "$HOME/Code/Shell/op.csv"
    else
        echo "$ip,not accessible" >> "$HOME/Code/Shell/op.csv"
    fi
done
